CREATE OR REPLACE FUNCTION fpa_wef_dead (ls_set text) RETURNS timestamp(0) AS $body$
DECLARE

ls_mm varchar(10);

BEGIN
     if (ls_set IS NOT NULL AND ls_set::text <> '') then
        ls_mm := trim(both substr(ls_set,position(' ' in ls_set),6));
        case ls_mm
          when 'ม.ค.' then ls_mm := '01';
          when 'ก.พ.' then ls_mm := '02';
          when 'มี.ค.' then ls_mm := '03';
          when 'เม.ย.' then ls_mm := '04';
          when 'พ.ค' then ls_mm := '05';
          when 'มิ.ย.' then ls_mm := '06';
          when 'ก.ค.' then ls_mm := '07';
          when 'ส.ค.' then ls_mm := '08';
          when 'ก.ย.' then ls_mm := '09';
          when 'ต.ค.' then ls_mm := '10';
          when 'พ.ย.' then ls_mm := '11';
          when 'ธ.ค.' then ls_mm := '12';
          else ls_mm := null;
        end case;
        ls_mm :=substr(ls_set,1,2)||'/'||trim(both substr(ls_mm,position(' ' in ls_mm),6))||'/'||'20'||right(ls_set,2);
    else
        NULL;
    end if;
    return ls_mm;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
